import{_ as t,c as i,o,ae as a}from"./chunks/framework.Cqi9LMMK.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{"title":"Introduction"},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),n={name:"guide/introduction.md"};function r(s,e,l,u,d,c){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="what-is-vue-inspector" tabindex="-1">What is Vue Inspector? <a class="header-anchor" href="#what-is-vue-inspector" aria-label="Permalink to &quot;What is Vue Inspector?&quot;">​</a></h2><p><strong>Vue Inspector</strong> is a tool for analyzing Vue applications at runtime without access to source code, a local build, or a dedicated dev environment.</p><p>The extension lets you explore the structure of the app on the open page: Props, Store, network requests, and internal component state as they exist while the app is running.</p><p>It is aimed at scenarios where you need to understand the frontend quickly without extra developer tooling.</p><hr><h2 id="when-use-vue-inspector" tabindex="-1">When use Vue Inspector? <a class="header-anchor" href="#when-use-vue-inspector" aria-label="Permalink to &quot;When use Vue Inspector?&quot;">​</a></h2><p>Vue Inspector helps when standard browser tooling is not enough or you need faster access to runtime data.</p><p>Main capabilities:</p><ul><li>View component props in real time;</li><li>Inspect received vs declared props;</li><li>Work with the store without manually hunting in runtime;</li><li>Browse network requests in a structured way;</li><li>Jump to related data inside the app;</li><li>Pick components on the page with Inspect mode;</li><li>Filter and locate data without walking the DOM by hand;</li></ul><hr><h2 id="how-is-it-different-from-standard-devtools" tabindex="-1">How is it different from standard DevTools? <a class="header-anchor" href="#how-is-it-different-from-standard-devtools" aria-label="Permalink to &quot;How is it different from standard DevTools?&quot;">​</a></h2><p>Unlike Vue Devtools, Vue Inspector targets not only local development but also already running apps where:</p><ul><li>there is no access to source code;</li><li>there is no local project build;</li><li>you need to explore production or test environments quickly;</li><li>you care about runtime data without preparing a dev setup;</li></ul><hr><h2 id="when-is-it-especially-useful" tabindex="-1">When is it especially useful? <a class="header-anchor" href="#when-is-it-especially-useful" aria-label="Permalink to &quot;When is it especially useful?&quot;">​</a></h2><p>Vue Inspector fits tasks such as:</p><ul><li>testing frontend applications;</li><li>analyzing complex integrations;</li><li>exploring component behavior;</li><li>tracking down data-flow issues;</li><li>checking reactive application state;</li></ul><hr><h2 id="more" tabindex="-1">More <a class="header-anchor" href="#more" aria-label="Permalink to &quot;More&quot;">​</a></h2><p>The project keeps evolving and expands runtime analysis for more frontend scenarios.</p>',21)])])}const m=t(n,[["render",r]]);export{h as __pageData,m as default};
